class Solution {
public:
    string smallestSubsequence(string s) {
        vector<int> count(26, 0);
        vector<bool> inRes(s.size(), false);
        for (int i = 0; i < s.size(); i++) count[s[i] - 'a']++;
        string res = "";
        for (int i = 0; i < s.size(); i++) {
            count[s[i] - 'a']--;
            if (inRes[i] || res.size() && res.back() <= s[i]) continue;
            while (res.size() && res.back() > s[i] && count[res.back() - 'a']) {
                inRes[res.size() - 1] = false;
                res.pop_back();
            }
            res += s[i];
            inRes[i] = true;
        }
        return res;
    }
};
